@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """
    Assertion Consumer Service (ACS) endpoint.
    This is where the IdP will POST the SAMLResponse after successful authentication.
    """
    app.logger.info("Received SAML ACS POST request.")
    saml_response_b64 = request.form.get('SAMLResponse')

    if not saml_response_b64:
        app.logger.error("SAMLResponse not found in POST request body.")
        return "SAMLResponse missing", 400

    try:
        # SAML responses are typically base64 encoded. They are usually not deflated.
        saml_response_xml = base64.b64decode(saml_response_b64).decode('utf-8')
        app.logger.debug(f"Decoded SAML Response:\n{saml_response_xml}")
    except Exception as e:
        app.logger.error(f"Error decoding SAMLResponse: {e}")
        return "Error decoding SAMLResponse", 400

    try:
        root = ET.fromstring(saml_response_xml)
    except ET.ParseError as e:
        app.logger.error(f"Error parsing SAMLResponse XML: {e}")
        return "Error parsing SAMLResponse XML", 400

    # Basic check for SAML Response Status
    status_node = find_xml_element(root, 'Status', SAML_PROTOCOL_NS)
    status_code_node = find_xml_element(status_node, 'StatusCode', SAML_PROTOCOL_NS) if status_node else None

    if not status_code_node or status_code_node.get('Value') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
        status_value = status_code_node.get('Value') if status_code_node else 'N/A'
        app.logger.error(f"SAML Response Status indicates failure: {status_value}")
        return f"SAML login failed: IdP returned status {status_value}", 403

    # --- Extract Assertion ---
    # Find the Assertion element. A SAMLResponse might contain multiple assertions
    # or an encrypted assertion. This example assumes a single, unencrypted assertion.
    assertion_node = find_xml_element(root, 'Assertion', SAML_ASSERTION_NS)
    if assertion_node is None:
        app.logger.error("No Assertion element found in SAML Response.")
        return "SAML login failed: No Assertion found", 403

    # --- IMPORTANT SECURITY NOTE ---
    # In a production environment, you MUST validate the digital signature of the
    # SAML Response or Assertion using the IdP's public certificate.
    # xml.etree.ElementTree does not provide this functionality out of the box.
    # You would typically use a library like 'python-xmlsec' for XML signature validation.
    # Skipping signature validation makes the system vulnerable to assertion forgery!
    app.logger.warning("SAML Signature Validation is SKIPPED. This is INSECURE for production!")
    # Additionally, validate:
    # - AudienceRestriction: Ensure the assertion is intended for this SP (SP_ENTITY_ID).
    # - NotOnOrAfter: Check the assertion's validity period.
    # - InResponseTo: Match with the original SAMLRequest ID (for SP-initiated flows).
    # - Issuer: Verify the IdP's entity ID.

    # --- Extract User Attributes ---
    user_id = None
    email = None
    first_name = None
    last_name = None
    attributes = {}

    # Extract NameID (Subject Identifier)
    subject_node = find_xml_element(assertion_node, 'Subject', SAML_ASSERTION_NS)
    if subject_node:
        name_id_node = find_xml_element(subject_node, 'NameID', SAML_ASSERTION_NS)
        if name_id_node is not None:
            user_id = name_id_node.text
            app.logger.info(f"Extracted NameID: {user_id} (Format: {name_id_node.get('Format')})")
            # The Format attribute (e.g., 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress')
            # indicates how to interpret the NameID.

    # Extract Attributes from AttributeStatement
    attribute_statement_node = find_xml_element(assertion_node, 'AttributeStatement', SAML_ASSERTION_NS)
    if attribute_statement_node:
        for attr_node in attribute_statement_node.findall(f'{{{SAML_ASSERTION_NS}}}Attribute'):
            attr_name = attr_node.get('Name')
            attr_friendly_name = attr_node.get('FriendlyName') # Often more readable than Name (URN/OID)
            
            # AttributeValue can have multiple values, handle the first one for simplicity
            attr_value_node = find_xml_element(attr_node, 'AttributeValue', SAML_ASSERTION_NS)
            if attr_value_node is not None:
                attr_value = attr_value_node.text
                
                # Store all attributes by their 'Name' (URN/OID)
                attributes[attr_name] = attr_value
                
                # Optionally, map to friendlier names if FriendlyName is present
                if attr_friendly_name:
                    attributes[attr_friendly_name] = attr_value
                
                app.logger.debug(f"Extracted Attribute: Name='{attr_name}' (FriendlyName='{attr_friendly_name}') Value='{attr_value}'")

                # Map common attributes to session variables for easier access
                if attr_name == 'email' or attr_name == 'urn:oid:0.9.2342.19200300.100.1.3': # urn:oid:0.9.2342.19200300.100.1.3 is 'mail'
                    email = attr_value
                elif attr_name == 'firstName' or attr_name == 'givenName' or attr_name == 'urn:oid:2.5.4.42': # urn:oid:2.5.4.42 is 'givenName'
                    first_name = attr_value
                elif attr_name == 'lastName' or attr_name == 'sn' or attr_name == 'urn:oid:2.5.4.4': # urn:oid:2.5.4.4 is 'sn'
                    last_name = attr_value
                elif attr_name == 'displayName':
                    # Sometimes NameID is not a human-readable name, so prefer displayName if available
                    if not user_id or 'urn:oasis:names:tc:SAML:2.0:nameid-format:transient' in name_id_node.get('Format', ''):
                        user_id = attr_value

    if not user_id:
        app.logger.error("Could not extract a primary user identifier (NameID or display name from attributes) from SAML Assertion.")
        return "SAML login failed: User ID not found", 403

    # --- Create User Session ---
    session['user_id'] = user_id
    session['email'] = email
    session['first_name'] = first_name
    session['last_name'] = last_name
    session['attributes'] = attributes # Store all extracted attributes
    app.logger.info(f"User '{user_id}' successfully logged in and session created.")

    # Redirect to a protected page or the original RelayState (if any)
    relay_state = request.form.get('RelayState', url_for('dashboard'))
    return redirect(relay_state)

